#!/usr/bin/env python3
import json
import re
import sys
from pathlib import Path


def read_text(root: Path, name: str) -> str:
    return (root / name).read_text(encoding="utf-8")


def extract_full_time_counts(roster: str) -> tuple[int, int]:
    m = re.search(r"Current FTE count:\s*(\d+)\s+full-time", roster)
    if not m:
        m = re.search(r"Full-Time Staff\s*\((\d+)\s+FTE\)", roster, re.I)
    if not m:
        raise ValueError("Could not extract actual full-time FTE count")
    actual = int(m.group(1))

    m = re.search(r"Target FTE count:\s*(\d+)\s+full-time", roster)
    if not m:
        raise ValueError("Could not extract target full-time FTE count")
    target = int(m.group(1))

    return actual, target


def extract_caresched_avg(hr: str) -> float:
    m = re.search(r"Average hours per FTE per week\s*\|\s*([0-9]+(?:\.[0-9]+)?)", hr)
    if not m:
        raise ValueError("Could not extract CareScheduler average weekly hours")
    return round(float(m.group(1)), 1)


def extract_legal_threshold(policy: str) -> int:
    m = re.search(
        r"Maximum weekly hours for full-time ICU nurses:\s*\*\*(\d+)\s+hours per week\*\*\s+per the Washington State Nursing Practice Act\s*\(WAC 246-840-711\)",
        policy,
        re.I,
    )
    if not m:
        m = re.search(r"WAC 246-840-711[^\n]*(\d+)[ -]?hour weekly maximum|(?:(\d+)\s+hours per week[^\n]*WAC 246-840-711)", policy, re.I)
    if not m:
        raise ValueError("Could not extract legal weekly-hours threshold")
    return int(next(g for g in m.groups() if g))


def main() -> None:
    if len(sys.argv) != 2:
        raise SystemExit("Usage: analyze_initial_staffing.py /path/to/workspace")

    root = Path(sys.argv[1])
    roster = read_text(root, "nurse_roster_current.md")
    hr = read_text(root, "hr_staffing_metrics.md")
    policy = read_text(root, "icu_staffing_policy.md")

    actual, target = extract_full_time_counts(roster)
    avg = extract_caresched_avg(hr)
    threshold = extract_legal_threshold(policy)

    result = {
        "fte_actual": actual,
        "fte_target": target,
        "fte_gap": target - actual,
        "caresched_avg": avg,
        "legal_threshold": threshold,
        "headroom_hours": round(threshold - avg, 1),
    }
    print(json.dumps(result, separators=(",", ":")))


if __name__ == "__main__":
    main()

